        int value;
        Node next;

        public Node(int val) {
            this.value = val;
            this.next = null;
        }
    }

    private static class LinkedList {
        Node head;

        public LinkedList() {
            head = null;
        }

        public void insertAtEnd(int val) {
            Node newNode = new Node(val);
            if (head == null) {
                head = newNode;
            } else {
                Node cur = head;
                while (cur.next != null) {
                    cur = cur.next;
                }
                cur.next = newNode;
            }
        }

        public int getLastValue() {
            if (head == null) {
                return -1;
            } else {
                Node cur = head;
                while (cur.next != null) {
                    cur = cur.next;
                }
                return cur.value;
            }
